/** Derive likely majors for a college based on its tags, type, and size */
export function getMajorsForCollege(college) {
  const m = new Set()
  // All schools offer these core liberal arts/sciences
  const core = ['Biology', 'Chemistry', 'English', 'History', 'Mathematics', 'Political Science', 'Psychology', 'Economics', 'Sociology', 'Philosophy', 'Communications']
  core.forEach(x => m.add(x))

  // Business programs
  if (college.tags.includes('business') || college.size !== 'small') {
    ;['Business Administration', 'Finance', 'Accounting', 'Marketing', 'Management'].forEach(x => m.add(x))
  }

  // Engineering & STEM
  if (college.tags.includes('engineering') || college.tags.includes('stem')) {
    ;['Computer Science', 'Mechanical Engineering', 'Electrical Engineering', 'Civil Engineering', 'Chemical Engineering', 'Aerospace Engineering', 'Biomedical Engineering', 'Computer Engineering', 'Industrial Engineering', 'Data Science', 'Statistics', 'Physics', 'Information Technology'].forEach(x => m.add(x))
  } else if (college.size === 'large' || college.tags.includes('research')) {
    ;['Computer Science', 'Data Science', 'Statistics', 'Physics', 'Information Technology'].forEach(x => m.add(x))
  }

  // Medical / Health
  if (college.tags.includes('medical')) {
    ;['Pre-Med', 'Nursing', 'Public Health', 'Health Sciences', 'Biochemistry', 'Neuroscience', 'Nutrition', 'Kinesiology'].forEach(x => m.add(x))
  } else if (college.size !== 'small') {
    ;['Pre-Med', 'Nursing', 'Public Health', 'Health Sciences'].forEach(x => m.add(x))
  }

  // Law
  if (college.tags.includes('law')) {
    ;['Pre-Law', 'Criminal Justice', 'International Relations'].forEach(x => m.add(x))
  }

  // Art & Design
  if (college.tags.includes('art-design')) {
    ;['Studio Art', 'Graphic Design', 'Art History', 'Film & Media', 'Performing Arts', 'Theater', 'Architecture'].forEach(x => m.add(x))
  }

  // Liberal arts focus
  if (college.tags.includes('liberal-arts')) {
    ;['Anthropology', 'Art History', 'Linguistics', 'Music', 'Performing Arts', 'Spanish', 'Theater', 'Religious Studies', 'Environmental Science', 'Neuroscience', 'Biochemistry', 'International Relations'].forEach(x => m.add(x))
  }

  // Religious schools
  if (college.tags.includes('religious')) {
    m.add('Religious Studies')
    m.add('Social Work')
  }

  // Large research universities get everything
  if (college.size === 'large' && college.tags.includes('research')) {
    ;['Anthropology', 'Architecture', 'Biochemistry', 'Criminal Justice', 'Education', 'Environmental Science', 'Film & Media', 'Graphic Design', 'Hospitality Management', 'International Relations', 'Journalism', 'Kinesiology', 'Linguistics', 'Music', 'Neuroscience', 'Nursing', 'Nutrition', 'Performing Arts', 'Pre-Law', 'Pre-Med', 'Public Health', 'Social Work', 'Spanish', 'Sports Management', 'Supply Chain Management', 'Theater', 'Urban Planning', 'Agriculture'].forEach(x => m.add(x))
  }

  // Medium+ schools
  if (college.size !== 'small') {
    ;['Education', 'Criminal Justice', 'Social Work', 'Environmental Science', 'Journalism', 'Sports Management'].forEach(x => m.add(x))
  }

  // HBCUs
  if (college.tags.includes('hbcu')) {
    ;['African American Studies', 'Social Work', 'Criminal Justice', 'Education'].forEach(x => m.add(x))
  }

  // Military
  if (college.tags.includes('military')) {
    ;['Aerospace Engineering', 'Mechanical Engineering', 'Civil Engineering', 'Computer Science', 'International Relations'].forEach(x => m.add(x))
  }

  return [...m].sort()
}

